import{G as t,c as e,b as s,ae as i}from"./chunks/framework.Cpb2nuHT.js";const r="/assets/2025-09-17-4cid9u.DnZ2oqxq.png",o="/assets/2025-09-17-B7uRGK.DTkQE6oF.png",l="/assets/2025-09-17-DVibr9.DirZ1c8e.png",p="/assets/2025-09-17-59RMNb.DXFZ3_6J.png",u=JSON.parse('{"title":"MyBatis的SQL执行结果和客户端相同SQL执行结果不一致问题","description":"","frontmatter":{"title":"MyBatis的SQL执行结果和客户端相同SQL执行结果不一致问题","date":"2025/4/9","author":"花木凋零成兰","tags":["Java","后端","Mybatis"],"hiddenCover":true},"headers":[],"relativePath":"后端开发问题/MyBatis的SQL执行结果和客户端相同SQL执行结果不一致问题.md","filePath":"后端开发问题/MyBatis的SQL执行结果和客户端相同SQL执行结果不一致问题.md","lastUpdated":1758072482000}'),n={name:"后端开发问题/MyBatis的SQL执行结果和客户端相同SQL执行结果不一致问题.md"};function d(c,a,_,h,m,b){return s(),e("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1744156800000"},[...a[0]||(a[0]=[i('<h1 id="mybatis的sql执行结果和客户端相同sql执行结果不一致问题" tabindex="-1">MyBatis的SQL执行结果和客户端相同SQL执行结果不一致问题 <a class="header-anchor" href="#mybatis的sql执行结果和客户端相同sql执行结果不一致问题" aria-label="Permalink to &quot;MyBatis的SQL执行结果和客户端相同SQL执行结果不一致问题&quot;">​</a></h1><p>在开发时候，我们使用MyBatis进行数据库操作，但是发现SQL执行结果和客户端执行结果不一致，导致出现一些问题。</p><h2 id="问题环境" tabindex="-1">问题环境 <a class="header-anchor" href="#问题环境" aria-label="Permalink to &quot;问题环境&quot;">​</a></h2><ul><li>Oracle 数据库</li></ul><h2 id="原因描述" tabindex="-1">原因描述 <a class="header-anchor" href="#原因描述" aria-label="Permalink to &quot;原因描述&quot;">​</a></h2><p>先描述出现Mybatis的SQL执行结果与客户端相同SQL执行结果不一致问题的原因, 是因为笔者在调试接口的时候, 参数是从某软件<strong>直接复制</strong>过来在 Apifox 粘贴并发送的;</p><p>问题就出在从别的软件直接复制过来上, 复制的时候携带了一个隐藏字符 [ZWNJ]; 这个字符的 Unicode 编码为 <code>U+200C</code> 是不可见的字符;</p><p>当参数携带了一个隐藏字符, 在Mybatis中构造SQL语句时, where 条件自然是无法成立的, 然后就会导致 SQL 的执行出现问题, 自然会出现与客户端SQL执行结果不一致的情况;</p><h2 id="问题发现" tabindex="-1">问题发现 <a class="header-anchor" href="#问题发现" aria-label="Permalink to &quot;问题发现&quot;">​</a></h2><p>经过多次调试和Debug, 笔者终于在文章: <a href="https://blog.csdn.net/modelmd/article/details/128460956" target="_blank" rel="noreferrer">MyBatis的SQL执行结果和客户端执行结果不一致问题排查</a> 中找到可能的问题所在;</p><p>使用 idea 自带的 Debug 最终发现了隐藏字符;</p><p><img src="'+r+'" alt="" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>此处为模拟场景</p></div><p>同时可以很显然发现, <strong>虽然 Debug 会将参数值在旁边标出来, 但是不点击打开, 使很难发现隐藏字符的</strong>;</p><p>我们可以查看控制台打印的 SQL 语句, 如下所示:</p><p><img src="'+o+'" alt="" loading="lazy"></p><p>是完全看不出问题所在的, 这个时候一般会将 SQL 复制到客户端中执行来尝试找到问题, Navicat客户端执行结果如下所示:</p><p><img src="'+l+'" alt="" loading="lazy"></p><p>上述语句更加突显了隐藏字符带来的影响, 直接复制 <code>%Jack%</code> 显然是包含了隐藏字符;</p><h2 id="问题总结" tabindex="-1">问题总结 <a class="header-anchor" href="#问题总结" aria-label="Permalink to &quot;问题总结&quot;">​</a></h2><p>本次能及时发现问题的原因, 是因为接口是 Get 接口, 本身参数不多, 也有先例可以参考; 在 Debug 的过程中, 使用笨方法, 一个一个参数点击开来是存在发现问题的可能性的;</p><p>可是不排除参数极多的情况, 在这种情况下, 难道一个一个参数进行点击吗?</p><p>尝试借助文本工具软件, 查看是否能显现隐藏字符, 采用软件有 Notepad++ 和 Windows自带的记事本, 结果如下:</p><p><img src="'+p+'" alt="" loading="lazy"></p><p>可以发现Windows的记事本显现了隐藏字符, 可以很容易看到奇怪的地方, 此外也可以尝试借助项目中的 <code>application.yml</code> 文件;</p><p>在日常的开发学习中, 我们要做的还是尽量避免问题, <strong>因此对于复制参数不长的情况, 可以尝试自己手打, 尽量将参数先复制到文本工具中, 再复制到 Apifox 中</strong>.</p><h2 id="参考文章" tabindex="-1">参考文章 <a class="header-anchor" href="#参考文章" aria-label="Permalink to &quot;参考文章&quot;">​</a></h2><ul><li><a href="https://blog.csdn.net/modelmd/article/details/128460956" target="_blank" rel="noreferrer">MyBatis的SQL执行结果和客户端执行结果不一致问题排查</a></li></ul>',28)])])}const S=t(n,[["render",d]]);export{u as __pageData,S as default};
